	@Test
	void legacyContextRebasesDescriptorMasksIntoOneUniverseBeyondTheFirstWord() {
		List<JoinFactorDescriptor> descriptors = new ArrayList<>();
		for (int index = 0; index < 70; index++) {
			String binding = "binding" + index;
			descriptors.add(new JoinFactorDescriptor(index, index,
					statementPattern("s" + index, "p", "o" + index), Set.of(binding), Set.of(binding),
					index == 69 ? Set.of("binding68") : Set.of()));
		}
		JoinSearchContext context = new JoinSearchContext(descriptors, Set.of("binding67"), PhysicalProperties.ANY,
				OptimizationGoal.BAG_SEMANTICS, OptimizationGoal.RowGoal.ALL,
				JoinFactorCostModel.EstimationTier.STANDARD);

		for (int index = 0; index < descriptors.size(); index++) {
			JoinFactorDescriptor descriptor = context.factor(index);
			assertThat(context.bindingUniverse().names(descriptor.possibleBindings()))
					.containsExactly("binding" + index);
			assertThat(context.bindingUniverse().names(descriptor.assuredBindings()))
					.containsExactly("binding" + index);
		}
		JoinFactorDescriptor finalDescriptor = context.factor(69);
		assertThat(finalDescriptor.possibleBindings().contains(context.bindingUniverse().symbol("binding69"))).isTrue();
		assertThat(context.bindingUniverse().names(finalDescriptor.requiredInputBindings()))
				.containsExactly("binding68");
		assertThat(context.initiallyBoundBindings().contains(context.bindingUniverse().symbol("binding67"))).isTrue();
	}

	@Test
	void contributorContextCarriesQueryLocalMasksBeyondTheFirstWord() throws Exception {
		BindingUniverse universe = BindingUniverse.create();
		List<String> names = new ArrayList<>();
		for (int index = 0; index < 70; index++) {
			names.add("binding" + index);
		}
		BindingMask possible = universe.maskOf(names);
		BindingMask required = universe.maskOf(Set.of("binding69"));

		Class<?> descriptorType = Class.forName(JOIN_PACKAGE + "JoinFactorDescriptor");
		Constructor<?> descriptorConstructor = descriptorType.getConstructor(int.class, int.class, TupleExpr.class,
				BindingUniverse.class, BindingMask.class, BindingMask.class, BindingMask.class);
		Object descriptor = descriptorConstructor.newInstance(0, 1, statementPattern("s", "p", "o"), universe,
				possible, possible, required);

		Class<?> contextType = Class.forName(JOIN_PACKAGE + "JoinSearchContext");
		Constructor<?> contextConstructor = contextType.getConstructor(List.class, BindingUniverse.class,
				BindingMask.class, PhysicalProperties.class, String.class, OptimizationGoal.RowGoal.class,
				JoinFactorCostModel.EstimationTier.class);
		Object context = contextConstructor.newInstance(List.of(descriptor), universe, required,
				PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS, OptimizationGoal.RowGoal.ALL,
				JoinFactorCostModel.EstimationTier.STANDARD);

		assertThat(invoke(descriptor, "possibleBindings")).isEqualTo(possible);
		assertThat(invoke(descriptor, "requiredInputBindings")).isEqualTo(required);
		assertThat(invoke(context, "bindingUniverse")).isSameAs(universe);
		assertThat(invokeUnchecked(context, "factor", int.class, 0)).isSameAs(descriptor);
		assertThat(invoke(context, "initiallyBoundBindings")).isEqualTo(required);
		assertThat(((BindingMask) invoke(context, "initiallyBoundBindings")).contains(universe.symbol("binding69")))
				.isTrue();
	}

	@Test
	void contributorContextIsOccurrenceScopedGoalAwareAndMutationIsolated() throws Exception {
		StatementPattern memoTemplate = statementPattern("s", "p", "o");
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		int sharedGroupId = memo.intern(memoTemplate);
		TupleExpr memoExpression = memo.group(sharedGroupId).expressions().get(0).tupleExpr();
		Set<String> possibleBindings = new LinkedHashSet<>(Set.of("s", "o"));
		Set<String> assuredBindings = new LinkedHashSet<>(Set.of("s"));
		Set<String> requiredInputBindings = new LinkedHashSet<>(Set.of("tenant"));

		Class<?> descriptorType = Class.forName(JOIN_PACKAGE + "JoinFactorDescriptor");
		Constructor<?> descriptorConstructor = descriptorType.getConstructor(int.class, int.class, TupleExpr.class,
				Set.class, Set.class, Set.class);
		Object firstOccurrence = descriptorConstructor.newInstance(10, sharedGroupId, memoExpression, possibleBindings,
				assuredBindings, requiredInputBindings);
		Object repeatedOccurrence = descriptorConstructor.newInstance(11, sharedGroupId,
				statementPattern("s", "p2", "related"), Set.of("s", "related"), Set.of("s"), Set.of());

		possibleBindings.add("late");
		assuredBindings.clear();
		requiredInputBindings.add("lateInput");

		PhysicalProperties requiredProperties = PhysicalProperties.builder()
				.ordering(List.of("s"))
				.inputBoundVars(Set.of("tenant"))
				.build();
		OptimizationGoal.RowGoal rowGoal = new OptimizationGoal.RowGoal(3L, 7L, true, false);
		Class<?> contextType = Class.forName(JOIN_PACKAGE + "JoinSearchContext");
		Constructor<?> contextConstructor = contextType.getConstructor(List.class, Set.class, PhysicalProperties.class,
				String.class, OptimizationGoal.RowGoal.class, JoinFactorCostModel.EstimationTier.class);
		List<Object> factorDescriptors = new ArrayList<>(List.of(firstOccurrence, repeatedOccurrence));
		Set<String> initiallyBoundVars = new LinkedHashSet<>(Set.of("tenant"));
		Object context = contextConstructor.newInstance(factorDescriptors, initiallyBoundVars,
				requiredProperties, OptimizationGoal.BAG_SEMANTICS, rowGoal,
				JoinFactorCostModel.EstimationTier.DECISION_EXACT);
		factorDescriptors.clear();
		initiallyBoundVars.add("lateInitialBinding");

		Method enumeration = JoinSearchRequest.class.getMethod("enumeration", JoinRegion.class,
				JoinSearchRequest.Mode.class, long.class, long.class, contextType);
		JoinRegion region = new JoinRegion(
				List.of(new JoinFactor(10, sharedGroupId), new JoinFactor(11, sharedGroupId)), List.of());
		JoinSearchRequest request = (JoinSearchRequest) enumeration.invoke(null, region,
				JoinSearchRequest.Mode.COMPLETE, 9L, 17L, context);

		assertThat(invoke(context, "initiallyBoundVars")).isEqualTo(Set.of("tenant"));
		assertThat(invoke(context, "requiredProperties")).isSameAs(requiredProperties);
		assertThat(invoke(context, "semanticScope")).isEqualTo(OptimizationGoal.BAG_SEMANTICS);
		assertThat(invoke(context, "rowGoal")).isEqualTo(rowGoal);
		assertThat(invoke(context, "estimationTier"))
				.isEqualTo(JoinFactorCostModel.EstimationTier.DECISION_EXACT);

		List<?> descriptors = castList(invoke(context, "factorDescriptors"));
		assertThat(descriptors).hasSize(2);
		assertThatThrownBy(() -> castListOfObjects(invoke(context, "factorDescriptors")).clear())
				.isInstanceOf(UnsupportedOperationException.class);
		assertThatThrownBy(() -> castSet(invoke(context, "initiallyBoundVars")).add("illegal"))
				.isInstanceOf(UnsupportedOperationException.class);
		assertThat(descriptors.stream().map(descriptor -> invokeUnchecked(descriptor, "occurrenceId")))
				.containsExactly(10, 11);
		assertThat(descriptors.stream().map(descriptor -> invokeUnchecked(descriptor, "groupId")))
				.containsExactly(sharedGroupId, sharedGroupId);
		assertThat(invoke(firstOccurrence, "possibleBindingNames")).isEqualTo(Set.of("s", "o"));
		assertThat(invoke(firstOccurrence, "assuredBindingNames")).isEqualTo(Set.of("s"));
		assertThat(invoke(firstOccurrence, "requiredInputBindingNames")).isEqualTo(Set.of("tenant"));
		assertThatThrownBy(() -> castSet(invoke(firstOccurrence, "possibleBindingNames")).add("illegal"))
				.isInstanceOf(UnsupportedOperationException.class);

		AtomicReference<TupleExpr> firstContributorTemplate = new AtomicReference<>();
		AtomicReference<TupleExpr> secondContributorTemplate = new AtomicReference<>();
		JoinSearchContributor mutatingContributor = contributor("mutating", 1, received -> {
			TupleExpr template = factorTemplate(received, 10);
			firstContributorTemplate.set(template);
			StatementPattern statementPattern = (StatementPattern) template;
			statementPattern.replaceChildNode(statementPattern.getSubjectVar(), Var.of("mutated"));
		});
		JoinSearchContributor observingContributor = contributor("observing", 2, received -> {
			TupleExpr template = factorTemplate(received, 10);
			secondContributorTemplate.set(template);
			assertThat(((StatementPattern) template).getSubjectVar().getName()).isEqualTo("s");
		});

		JoinSearchService service = new JoinSearchService(List.of(mutatingContributor, observingContributor,
				new ExhaustiveLegalJoinSearchContributor()));
		JoinEnumerationResult result = service.enumerate(request);

		assertThat(result.complete()).isTrue();
		assertThat(firstContributorTemplate.get()).isNotSameAs(secondContributorTemplate.get());
		assertThat(memoTemplate.getSubjectVar().getName()).isEqualTo("s");
		assertThat(((StatementPattern) memo.group(sharedGroupId).expressions().get(0).tupleExpr())
				.getSubjectVar()
				.getName()).isEqualTo("s");
		assertThat(((StatementPattern) factorTemplate(request, 10)).getSubjectVar().getName()).isEqualTo("s");
	}

